class Cache {
 Map<Integer, Integer> keyValueMap;
 Map<Integer, Integer> keyIndiceMap;
 List<Integer> keyList;
 int next;
 Random random;

public Cache() {
 keyValueMap = new HashMap<>();
 keyIndiceMap = new HashMap<>();
 keyList = new ArrayList<>();
 next = 0;
 random = new Random();
}

public void add(int key, int val) {
 if(!keyIndiceMap.containsKey(key)) {
  keyIndiceMap.put(key, next);
  if(next==keyList.size()) keyList.add(key);
  next++;
 }
 keyValueMap.put(key, val);
}

public void remove(int key) {
 if(!keyIndiceMap.containsKey(key)) return;
 int index = keyIndiceMap.get(key);
 Collections.swap(keyList, next-1, index);
 next--;
 keyIndiceMap.remove(key);
 keyValueMap.remove(key);
}

public int get(int key) {
 if(!keyValueMap.containsKey(key)) return -1;
 return keyValueMap.get(key);
}

public int getRandom() { 
 int randIndex = random.nextInt(next);
 return keyValueMap.get(keyList.get(randIndex));
}

}
```
