public List<String[]> settle(String[][] transactions) {
 Map<String, Map<String, Integer>> map = new HashMap<>();
 for(String[] transaction : transactions) {
  String sender = transaction[0], receiver = transaction[1];
  int money = Integer.valueOf(transaction[2]);
  if(map.containsKey(receiver) && map.get(receiver).containsKey(sender)) {
   map.get(receiver).put(sender, map.get(receiver).get(sender)-money);
  } else {
   map.computeIfAbsent(sender, x->new HashMap<>()).put(receiver, money);
  }
 }
 List<String[]> ans = new ArrayList<>();
 for(String sender: map.keySet()) {
  for(String receiver : map.get(sender).keySet()) {
   int money = map.get(sender).get(receiver);
   if(money<0) ans.add(new String[]{receiver, sender, String.valueOf(-1*money)});
   else ans.add(new String[]{sender, receiver, String.valueOf(money)});
  }
 }
 return ans;
}
